func (gs *GameServer) addClient(conn net.Conn, username string, role UserRole) {
	client := &Client{
		conn:     conn,
		username: username,
		role:     role,
	}
	
	gs.mu.Lock()
	gs.clients[client] = true
	gs.mu.Unlock()
	
	go gs.handleClient(client)
}

func (gs *GameServer) removeClient(client *Client) {
	gs.mu.Lock()
	delete(gs.clients, client)
	gs.mu.Unlock()
	
	client.conn.Close()
}

func (gs *GameServer) handleClient(client *Client) {
	defer gs.removeClient(client)
	
	scanner := bufio.NewScanner(client.conn)
	
	for scanner.Scan() {
		message := scanner.Text()
		
		if strings.HasPrefix(message, "/") {
			gs.processCommand(client, message)
		} else {
			gs.broadcastMessage(client, message)
		}
	}
}

func (gs *GameServer) processCommand(client *Client, message string) {
	parts := strings.Fields(message)
	if len(parts) == 0 {
		return
	}
	
	commandName := parts[0]
	
	cmd, exists := gs.commands[commandName]
	if !exists {
		client.conn.Write([]byte("Unknown command. Type /help for available commands.\n"))
		return
	}
	
	if cmd.minRole > client.role {
		client.conn.Write([]byte("You do not have permission to use this command.\n"))
		return
	}
	
	args := parts[1:]
	cmd.handler(client, args)
}

func (gs *GameServer) broadcastMessage(sender *Client, message string) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()
	
	for client, _ := range gs.clients {
		if client != sender {
			client.conn.Write([]byte(fmt.Sprintf("%s: %s\n", sender.username, message)))
		}
	}
}

func (gs *GameServer) Start(address string) error {
	listener, err := net.Listen("tcp", address)
	if err != nil {
		return err
	}
	defer listener.Close()
	
	fmt.Printf("Game server listening on %s\n", address)
	
	for {
		conn, err := listener.Accept()
		if err != nil {
			fmt.Printf("Error accepting connection: %v\n", err)
			continue
		}
		
		go gs.handleConnection(conn)
	}
}

